import React, { useState, useEffect, useRef } from "react";

export default function GameScreen({
  role, word, round, totalRounds,
  players, playerId, submitted, submittedCount, totalCount,
  onSubmit,
}) {
  const [text, setText]         = useState("");
  const [timeLeft, setTimeLeft] = useState(60);
  const [done, setDone]         = useState(false);
  const timerRef                = useRef(null);

  useEffect(() => {
    setTimeLeft(60);
    setDone(false);
    setText("");
    timerRef.current = setInterval(() => {
      setTimeLeft(t => {
        if (t <= 1) { clearInterval(timerRef.current); return 0; }
        return t - 1;
      });
    }, 1000);
    return () => clearInterval(timerRef.current);
  }, [round]);

  const handleSubmit = () => {
    if (!text.trim() || done) return;
    setDone(true);
    clearInterval(timerRef.current);
    onSubmit(text.trim());
  };

  const isImpostor   = role === "impostor";
  const timerColor   = timeLeft <= 10 ? "#e63946" : timeLeft <= 20 ? "#ff9f1c" : "#2ec4b6";

  return (
    <div className="game-page">
      <div className="game-topbar">
        <div className="round-badge">Round {round} / {totalRounds}</div>
        <div className="timer-ring">
          <svg viewBox="0 0 48 48">
            <circle cx="24" cy="24" r="20" fill="none" stroke="#1e2535" strokeWidth="4"/>
            <circle cx="24" cy="24" r="20" fill="none"
              stroke={timerColor} strokeWidth="4"
              strokeDasharray={`${(timeLeft / 60) * 125.6} 125.6`}
              strokeLinecap="round"
              transform="rotate(-90 24 24)"
              style={{ transition: "stroke-dasharray 1s linear, stroke 0.3s" }}
            />
          </svg>
          <span className="timer-num" style={{ color: timerColor }}>{timeLeft}</span>
        </div>
        <div className="sub-count">{submittedCount}/{totalCount} submitted</div>
      </div>

      <div className={`word-card ${isImpostor ? "impostor-card" : "crewmate-card"}`}>
        <p className="role-label">{isImpostor ? "🕵️ You are the IMPOSTOR" : "🧑‍🚀 Your secret word is"}</p>
        <h2 className="secret-word">{word}</h2>
        {isImpostor && (
          <p className="impostor-hint">Blend in! Describe something that could match the real word.</p>
        )}
      </div>

      <div className="desc-section">
        <label className="desc-label">Your one-sentence description:</label>
        <textarea
          className="desc-input"
          placeholder={isImpostor ? "e.g. It looks very colourful and is usually found outside…" : `Describe "${word}" in one sentence…`}
          maxLength={120}
          rows={3}
          value={text}
          disabled={done || submitted}
          onChange={e => setText(e.target.value)}
        />
        <div className="desc-footer">
          <span className="char-count">{text.length}/120</span>
          <button
            className="btn btn-submit"
            onClick={handleSubmit}
            disabled={done || submitted || !text.trim()}
          >
            {done || submitted ? "✓ Submitted!" : "Submit Description"}
          </button>
        </div>
      </div>

      <div className="players-status">
        {players.map((p, i) => (
          <div key={p._id} className={`status-chip ${p._id === playerId ? "you-chip" : ""}`}>
            <div className="chip-av" style={{ background: avatarColor(i) }}>
              {p.name[0].toUpperCase()}
            </div>
            <span>{p.name}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

const COLORS = ["#e63946","#457b9d","#2ec4b6","#ff9f1c","#8338ec","#06d6a0","#ef476f","#118ab2"];
function avatarColor(i) { return COLORS[i % COLORS.length]; }
